 86→// NewMergeChunkQuerier returns a new Chunk Querier that merges results of given primary and secondary chunk queriers.
 87→// See NewFanout commentary to learn more about primary vs secondary differences.
 88→//
 89→// In case of overlaps between the data given by primaries' and secondaries' Selects, merge function will be used.
 90→// TODO(bwplotka): Currently merge will compact overlapping chunks with bigger chunk, without limit. Split it: https://github.com/prometheus/tsdb/issues/670
 91→func NewMergeChunkQuerier(primaries, secondaries []ChunkQuerier, mergeFn VerticalChunkSeriesMergeFunc) ChunkQuerier {
 92→	primaries = filterChunkQueriers(primaries)
 93→	secondaries = filterChunkQueriers(secondaries)
 94→
 95→	switch {
 96→	case len(primaries) == 0 && len(secondaries) == 0:
 97→		return noopChunkQuerier{}
 98→	case len(primaries) == 1 && len(secondaries) == 0:
 99→		return primaries[0]
100→	case len(primaries) == 0 && len(secondaries) == 1:
101→		return &chunkQuerierAdapter{newSecondaryQuerierFromChunk(secondaries[0])}
102→	}
103→
104→	queriers := make([]genericQuerier, 0, len(primaries)+len(secondaries))
105→	for _, q := range primaries {
106→		queriers = append(queriers, newGenericQuerierFromChunk(q))
107→	}
108→	for _, q := range secondaries {
109→		queriers = append(queriers, newSecondaryQuerierFromChunk(q))
110→	}
111→
112→	concurrentSelect := len(secondaries) > 0
113→
114→	return &chunkQuerierAdapter{&mergeGenericQuerier{
115→		mergeFn:          (&chunkSeriesMergerAdapter{VerticalChunkSeriesMergeFunc: mergeFn}).Merge,
116→		queriers:         queriers,
117→		concurrentSelect: concurrentSelect,
118→	}}
119→}
120→
121→func filterChunkQueriers(qs []ChunkQuerier) []ChunkQuerier {
122→	ret := make([]ChunkQuerier, 0, len(qs))
123→	for _, q := range qs {
124→		if _, ok := q.(noopChunkQuerier); !ok && q != nil {
125→			ret = append(ret, q)
126→		}
127→	}
128→	return ret
129→}
130→
131→// Select returns a set of series that matches the given label matchers.
132→func (q *mergeGenericQuerier) Select(ctx context.Context, _ bool, hints *SelectHints, matchers ...*labels.Matcher) genericSeriesSet {
133→	seriesSets := make([]genericSeriesSet, 0, len(q.queriers))
134→	var limit int
135→	if hints != nil {
136→		limit = hints.Limit
137→	}
138→	if !q.concurrentSelect {
139→		for _, querier := range q.queriers {
140→			// We need to sort for merge  to work.
141→			seriesSets = append(seriesSets, querier.Select(ctx, true, hints, matchers...))
142→		}
143→		return &lazyGenericSeriesSet{init: func() (genericSeriesSet, bool) {
144→			s := newGenericMergeSeriesSet(seriesSets, limit, q.mergeFn)
145→			return s, s.Next()
146→		}}
147→	}
148→
149→	var (
150→		wg            sync.WaitGroup
151→		seriesSetChan = make(chan genericSeriesSet)
152→	)
153→	// Schedule all Selects for all queriers we know about.
154→	for _, querier := range q.queriers {
155→		// copy the matchers as some queriers may alter the slice.
156→		// See https://github.com/prometheus/prometheus/issues/14723
157→		matchersCopy := make([]*labels.Matcher, len(matchers))
158→		copy(matchersCopy, matchers)
159→
160→		wg.Add(1)
161→		go func(qr genericQuerier, m []*labels.Matcher) {
162→			defer wg.Done()
163→
164→			// We need to sort for NewMergeSeriesSet to work.
165→			seriesSetChan <- qr.Select(ctx, true, hints, m...)
166→		}(querier, matchersCopy)
167→	}
168→	go func() {
169→		wg.Wait()
170→		close(seriesSetChan)
171→	}()
172→
173→	for r := range seriesSetChan {
174→		seriesSets = append(seriesSets, r)
175→	}
176→	return &lazyGenericSeriesSet{init: func() (genericSeriesSet, bool) {
177→		s := newGenericMergeSeriesSet(seriesSets, limit, q.mergeFn)
178→		return s, s.Next()
179→	}}
180→}
