182→type labelGenericQueriers []genericQuerier
183→
184→func (l labelGenericQueriers) Len() int               { return len(l) }
185→func (l labelGenericQueriers) Get(i int) LabelQuerier { return l[i] }
186→func (l labelGenericQueriers) SplitByHalf() (labelGenericQueriers, labelGenericQueriers) {
187→	i := len(l) / 2
188→	return l[:i], l[i:]
189→}
