204→// mergeResults performs merge sort on the results of invoking the resultsFn against multiple queriers.
205→func (q *mergeGenericQuerier) mergeResults(lq labelGenericQueriers, hints *LabelHints, resultsFn func(q LabelQuerier) ([]string, annotations.Annotations, error)) ([]string, annotations.Annotations, error) {
206→	if lq.Len() == 0 {
207→		return nil, nil, nil
208→	}
209→	if lq.Len() == 1 {
210→		return resultsFn(lq.Get(0))
211→	}
212→	a, b := lq.SplitByHalf()
213→
214→	var ws annotations.Annotations
215→	s1, w, err := q.mergeResults(a, hints, resultsFn)
216→	ws.Merge(w)
217→	if err != nil {
218→		return nil, ws, err
219→	}
220→	s2, w, err := q.mergeResults(b, hints, resultsFn)
221→	ws.Merge(w)
222→	if err != nil {
223→		return nil, ws, err
224→	}
225→
226→	s1 = truncateToLimit(s1, hints)
227→	s2 = truncateToLimit(s2, hints)
228→
229→	merged := mergeStrings(s1, s2)
230→	merged = truncateToLimit(merged, hints)
231→
232→	return merged, ws, nil
233→}
234→
235→func mergeStrings(a, b []string) []string {
236→	maxl := max(len(b), len(a))
237→	res := make([]string, 0, maxl*10/9)
238→
239→	for len(a) > 0 && len(b) > 0 {
240→		switch {
241→		case a[0] == b[0]:
242→			res = append(res, a[0])
243→			a, b = a[1:], b[1:]
244→		case a[0] < b[0]:
245→			res = append(res, a[0])
246→			a = a[1:]
247→		default:
248→			res = append(res, b[0])
249→			b = b[1:]
250→		}
251→	}
252→
253→	// Append all remaining elements.
254→	res = append(res, a...)
255→	res = append(res, b...)
256→	return res
257→}
258→
259→// LabelNames returns all the unique label names present in all queriers in sorted order.
260→func (q *mergeGenericQuerier) LabelNames(ctx context.Context, hints *LabelHints, matchers ...*labels.Matcher) ([]string, annotations.Annotations, error) {
261→	res, ws, err := q.mergeResults(q.queriers, hints, func(q LabelQuerier) ([]string, annotations.Annotations, error) {
262→		return q.LabelNames(ctx, hints, matchers...)
263→	})
264→	if err != nil {
265→		return nil, nil, fmt.Errorf("LabelNames() from merge generic querier: %w", err)
266→	}
267→	return res, ws, nil
268→}
269→
270→// Close releases the resources of the generic querier.
271→func (q *mergeGenericQuerier) Close() error {
272→	var errs []error
273→	for _, querier := range q.queriers {
274→		if err := querier.Close(); err != nil {
275→			errs = append(errs, err)
276→		}
277→	}
278→	return errors.Join(errs...)
279→}
