317→// genericMergeSeriesSet implements genericSeriesSet.
318→type genericMergeSeriesSet struct {
319→	currentLabels labels.Labels
320→	mergeFunc     genericSeriesMergeFunc
321→
322→	heap         genericSeriesSetHeap
323→	sets         []genericSeriesSet
324→	currentSets  []genericSeriesSet
325→	seriesLimit  int
326→	mergedSeries int // tracks the total number of series merged and returned.
327→}
328→
329→// newGenericMergeSeriesSet returns a new genericSeriesSet that merges (and deduplicates)
330→// series returned by the series sets when iterating.
331→// Each series set must return its series in labels order, otherwise
332→// merged series set will be incorrect.
333→// Overlapped situations are merged using provided mergeFunc.
334→// If seriesLimit is set, only limited series are returned.
335→func newGenericMergeSeriesSet(sets []genericSeriesSet, seriesLimit int, mergeFunc genericSeriesMergeFunc) genericSeriesSet {
336→	if len(sets) == 1 {
337→		return sets[0]
338→	}
339→
340→	// We are pre-advancing sets, so we can introspect the label of the
341→	// series under the cursor.
342→	var h genericSeriesSetHeap
343→	for _, set := range sets {
344→		if set == nil {
345→			continue
346→		}
347→		if set.Next() {
348→			heap.Push(&h, set)
349→		}
350→		if err := set.Err(); err != nil {
351→			return errorOnlySeriesSet{err}
352→		}
353→	}
354→	return &genericMergeSeriesSet{
355→		mergeFunc:   mergeFunc,
356→		sets:        sets,
357→		heap:        h,
358→		seriesLimit: seriesLimit,
359→	}
360→}
361→
362→func (c *genericMergeSeriesSet) Next() bool {
363→	if c.seriesLimit > 0 && c.mergedSeries >= c.seriesLimit {
364→		// Exit early if seriesLimit is set.
365→		return false
366→	}
367→
368→	// Run in a loop because the "next" series sets may not be valid anymore.
369→	// If, for the current label set, all the next series sets come from
370→	// failed remote storage sources, we want to keep trying with the next label set.
371→	for {
372→		// Firstly advance all the current series sets. If any of them have run out,
373→		// we can drop them, otherwise they should be inserted back into the heap.
374→		for _, set := range c.currentSets {
375→			if set.Next() {
376→				heap.Push(&c.heap, set)
377→			}
378→		}
379→
380→		if len(c.heap) == 0 {
381→			return false
382→		}
383→
384→		// Now, pop items of the heap that have equal label sets.
385→		c.currentSets = c.currentSets[:0]
386→		c.currentLabels = c.heap[0].At().Labels()
387→		for len(c.heap) > 0 && labels.Equal(c.currentLabels, c.heap[0].At().Labels()) {
388→			set := heap.Pop(&c.heap).(genericSeriesSet)
389→			c.currentSets = append(c.currentSets, set)
390→		}
391→
392→		// As long as the current set contains at least 1 set,
393→		// then it should return true.
394→		if len(c.currentSets) != 0 {
395→			break
396→		}
397→	}
398→	c.mergedSeries++
399→	return true
400→}
401→
402→func (c *genericMergeSeriesSet) At() Labels {
403→	if len(c.currentSets) == 1 {
404→		return c.currentSets[0].At()
405→	}
406→	series := make([]Labels, 0, len(c.currentSets))
407→	for _, seriesSet := range c.currentSets {
408→		series = append(series, seriesSet.At())
409→	}
410→	return c.mergeFunc(series...)
411→}
412→
413→func (c *genericMergeSeriesSet) Err() error {
414→	for _, set := range c.sets {
415→		if err := set.Err(); err != nil {
416→			return err
417→		}
418→	}
419→	return nil
420→}
421→
422→func (c *genericMergeSeriesSet) Warnings() annotations.Annotations {
423→	var ws annotations.Annotations
424→	for _, set := range c.sets {
425→		ws.Merge(set.Warnings())
426→	}
427→	return ws
428→}
