430→type genericSeriesSetHeap []genericSeriesSet
431→
432→func (h genericSeriesSetHeap) Len() int      { return len(h) }
433→func (h genericSeriesSetHeap) Swap(i, j int) { h[i], h[j] = h[j], h[i] }
434→
435→func (h genericSeriesSetHeap) Less(i, j int) bool {
436→	a, b := h[i].At().Labels(), h[j].At().Labels()
437→	return labels.Compare(a, b) < 0
438→}
439→
440→func (h *genericSeriesSetHeap) Push(x any) {
441→	*h = append(*h, x.(genericSeriesSet))
442→}
443→
444→func (h *genericSeriesSetHeap) Pop() any {
445→	old := *h
446→	n := len(old)
447→	x := old[n-1]
448→	*h = old[0 : n-1]
449→	return x
450→}
451→
452→// ChainedSeriesMerge returns single series from many same, potentially overlapping series by chaining samples together.
453→// If one or more samples overlap, one sample from random overlapped ones is kept and all others with the same
454→// timestamp are dropped.
455→//
456→// This works the best with replicated series, where data from two series are exactly the same. This does not work well
457→// with "almost" the same data, e.g. from 2 Prometheus HA replicas. This is fine, since from the Prometheus perspective
458→// this never happens.
459→//
460→// It's optimized for non-overlap cases as well.
461→func ChainedSeriesMerge(series ...Series) Series {
462→	if len(series) == 0 {
463→		return nil
464→	}
465→	return &SeriesEntry{
466→		Lset: series[0].Labels(),
467→		SampleIteratorFn: func(it chunkenc.Iterator) chunkenc.Iterator {
468→			return ChainSampleIteratorFromSeries(it, series)
469→		},
470→	}
471→}
472→
473→// chainSampleIterator is responsible to iterate over samples from different iterators of the same time series in timestamps
474→// order. If one or more samples overlap, one sample from random overlapped ones is kept and all others with the same
475→// timestamp are dropped. It's optimized for non-overlap cases as well.
476→type chainSampleIterator struct {
477→	iterators []chunkenc.Iterator
478→	h         samplesIteratorHeap
479→
480→	curr  chunkenc.Iterator
481→	lastT int64
482→
483→	// Whether the previous and the current sample are direct neighbors
484→	// within the same base iterator.
485→	consecutive bool
486→}
487→
488→// Return a chainSampleIterator initialized for length entries, re-using the memory from it if possible.
489→func getChainSampleIterator(it chunkenc.Iterator, length int) *chainSampleIterator {
490→	csi, ok := it.(*chainSampleIterator)
491→	if !ok {
492→		csi = &chainSampleIterator{}
493→	}
494→	if cap(csi.iterators) < length {
495→		csi.iterators = make([]chunkenc.Iterator, length)
496→	} else {
497→		csi.iterators = csi.iterators[:length]
498→	}
499→	csi.h = nil
500→	csi.lastT = math.MinInt64
501→	return csi
502→}
503→
504→func ChainSampleIteratorFromSeries(it chunkenc.Iterator, series []Series) chunkenc.Iterator {
505→	csi := getChainSampleIterator(it, len(series))
506→	for i, s := range series {
507→		csi.iterators[i] = s.Iterator(csi.iterators[i])
508→	}
509→	return csi
510→}
511→
512→func ChainSampleIteratorFromIterables(it chunkenc.Iterator, iterables []chunkenc.Iterable) chunkenc.Iterator {
513→	csi := getChainSampleIterator(it, len(iterables))
514→	for i, c := range iterables {
515→		csi.iterators[i] = c.Iterator(csi.iterators[i])
516→	}
517→	return csi
518→}
519→
520→func ChainSampleIteratorFromIterators(it chunkenc.Iterator, iterators []chunkenc.Iterator) chunkenc.Iterator {
521→	csi := getChainSampleIterator(it, 0)
522→	csi.iterators = iterators
523→	return csi
524→}
525→
526→func (c *chainSampleIterator) Seek(t int64) chunkenc.ValueType {
527→	// No-op check.
528→	if c.curr != nil && c.lastT >= t {
529→		return c.curr.Seek(c.lastT)
530→	}
531→	// Don't bother to find out if the next sample is consecutive. Callers
532→	// of Seek usually aren't interested anyway.
533→	c.consecutive = false
534→	c.h = samplesIteratorHeap{}
535→	for _, iter := range c.iterators {
536→		if iter.Seek(t) == chunkenc.ValNone {
537→			if iter.Err() != nil {
538→				// If any iterator is reporting an error, abort.
539→				return chunkenc.ValNone
540→			}
541→			continue
542→		}
543→		heap.Push(&c.h, iter)
544→	}
545→	if len(c.h) > 0 {
546→		c.curr = heap.Pop(&c.h).(chunkenc.Iterator)
547→		c.lastT = c.curr.AtT()
548→		return c.curr.Seek(c.lastT)
549→	}
550→	c.curr = nil
551→	return chunkenc.ValNone
552→}
553→
554→func (c *chainSampleIterator) At() (t int64, v float64) {
555→	if c.curr == nil {
556→		panic("chainSampleIterator.At called before first .Next or after .Next returned false.")
557→	}
558→	return c.curr.At()
559→}
560→
561→func (c *chainSampleIterator) AtHistogram(h *histogram.Histogram) (int64, *histogram.Histogram) {
562→	if c.curr == nil {
563→		panic("chainSampleIterator.AtHistogram called before first .Next or after .Next returned false.")
564→	}
565→	t, h := c.curr.AtHistogram(h)
566→	// If the current sample is not consecutive with the previous one, we
567→	// cannot be sure anymore about counter resets for counter histograms.
568→	// TODO(beorn7): If a `NotCounterReset` sample is followed by a
569→	// non-consecutive `CounterReset` sample, we could keep the hint as
570→	// `CounterReset`. But then we needed to track the previous sample
571→	// in more detail, which might not be worth it.
572→	if !c.consecutive && h.CounterResetHint != histogram.GaugeType {
573→		h.CounterResetHint = histogram.UnknownCounterReset
574→	}
575→	return t, h
576→}
577→
578→func (c *chainSampleIterator) AtFloatHistogram(fh *histogram.FloatHistogram) (int64, *histogram.FloatHistogram) {
579→	if c.curr == nil {
580→		panic("chainSampleIterator.AtFloatHistogram called before first .Next or after .Next returned false.")
581→	}
582→	t, fh := c.curr.AtFloatHistogram(fh)
583→	// If the current sample is not consecutive with the previous one, we
584→	// cannot be sure anymore about counter resets for counter histograms.
585→	// TODO(beorn7): If a `NotCounterReset` sample is followed by a
586→	// non-consecutive `CounterReset` sample, we could keep the hint as
587→	// `CounterReset`. But then we needed to track the previous sample
588→	// in more detail, which might not be worth it.
589→	if !c.consecutive && fh.CounterResetHint != histogram.GaugeType {
590→		fh.CounterResetHint = histogram.UnknownCounterReset
591→	}
592→	return t, fh
593→}
594→
595→func (c *chainSampleIterator) AtT() int64 {
596→	if c.curr == nil {
597→		panic("chainSampleIterator.AtT called before first .Next or after .Next returned false.")
598→	}
599→	return c.curr.AtT()
600→}
601→
602→func (c *chainSampleIterator) AtST() int64 {
603→	if c.curr == nil {
604→		panic("chainSampleIterator.AtST called before first .Next or after .Next returned false.")
605→	}
606→	return c.curr.AtST()
607→}
608→
609→func (c *chainSampleIterator) Next() chunkenc.ValueType {
610→	var (
611→		currT           int64
612→		currValueType   chunkenc.ValueType
613→		iteratorChanged bool
614→	)
615→	if c.h == nil {
616→		iteratorChanged = true
617→		c.h = samplesIteratorHeap{}
618→		// We call c.curr.Next() as the first thing below.
619→		// So, we don't call Next() on it here.
620→		c.curr = c.iterators[0]
621→		for _, iter := range c.iterators[1:] {
622→			if iter.Next() == chunkenc.ValNone {
623→				if iter.Err() != nil {
624→					// If any iterator is reporting an error, abort.
625→					// If c.iterators[0] is reporting an error, we'll handle that below.
626→					return chunkenc.ValNone
627→				}
628→			} else {
629→				heap.Push(&c.h, iter)
630→			}
631→		}
632→	}
633→
634→	if c.curr == nil {
635→		return chunkenc.ValNone
636→	}
637→
638→	for {
639→		currValueType = c.curr.Next()
640→
641→		if currValueType == chunkenc.ValNone {
642→			if c.curr.Err() != nil {
643→				// Abort if we've hit an error.
644→				return chunkenc.ValNone
645→			}
646→
647→			if len(c.h) == 0 {
648→				// No iterator left to iterate.
649→				c.curr = nil
650→				return chunkenc.ValNone
651→			}
652→		} else {
653→			currT = c.curr.AtT()
654→			if currT == c.lastT {
655→				// Ignoring sample for the same timestamp.
656→				continue
657→			}
658→			if len(c.h) == 0 {
659→				// curr is the only iterator remaining,
660→				// no need to check with the heap.
661→				break
662→			}
663→
664→			// Check current iterator with the top of the heap.
665→			nextT := c.h[0].AtT()
666→			if currT < nextT {
667→				// Current iterator has smaller timestamp than the heap.
668→				break
669→			}
670→			// Current iterator does not hold the smallest timestamp.
671→			heap.Push(&c.h, c.curr)
672→		}
673→
674→		c.curr = heap.Pop(&c.h).(chunkenc.Iterator)
675→		iteratorChanged = true
676→		currT = c.curr.AtT()
677→		currValueType = c.curr.Seek(currT)
678→		if currT != c.lastT {
679→			break
680→		}
681→	}
682→
683→	c.consecutive = !iteratorChanged
684→	c.lastT = currT
685→	return currValueType
