745→// compactChunkIterator is responsible to compact chunks from different iterators of the same time series into single chainSeries.
746→// If time-overlapping chunks are found, they are encoded and passed to series merge and encoded again into one bigger chunk.
747→// TODO(bwplotka): Currently merge will compact overlapping chunks with bigger chunk, without limit. Split it: https://github.com/prometheus/tsdb/issues/670
748→type compactChunkIterator struct {
749→	mergeFunc VerticalSeriesMergeFunc
750→	iterators []chunks.Iterator
751→
752→	h chunkIteratorHeap
753→
754→	err  error
755→	curr chunks.Meta
756→}
