762→func (c *compactChunkIterator) Next() bool {
763→	if c.h == nil {
764→		for _, iter := range c.iterators {
765→			if iter.Next() {
766→				heap.Push(&c.h, iter)
767→			}
768→		}
769→	}
770→	if len(c.h) == 0 {
771→		return false
772→	}
773→
774→	iter := heap.Pop(&c.h).(chunks.Iterator)
775→	c.curr = iter.At()
776→	if iter.Next() {
777→		heap.Push(&c.h, iter)
778→	}
779→
780→	var (
781→		overlapping []Series
782→		oMaxTime    = c.curr.MaxTime
783→		prev        = c.curr
784→	)
785→	// Detect overlaps to compact. Be smart about it and deduplicate on the fly if chunks are identical.
786→	for len(c.h) > 0 {
787→		// Get the next oldest chunk by min, then max time.
788→		next := c.h[0].At()
789→		if next.MinTime > oMaxTime {
790→			// No overlap with current one.
791→			break
792→		}
793→
794→		// Only do something if it is not a perfect duplicate.
795→		if next.MinTime != prev.MinTime ||
796→			next.MaxTime != prev.MaxTime ||
797→			!bytes.Equal(next.Chunk.Bytes(), prev.Chunk.Bytes()) {
798→			// We operate on same series, so labels do not matter here.
799→			overlapping = append(overlapping, newChunkToSeriesDecoder(labels.EmptyLabels(), next))
800→			if next.MaxTime > oMaxTime {
801→				oMaxTime = next.MaxTime
802→			}
803→			prev = next
804→		}
805→
806→		iter := heap.Pop(&c.h).(chunks.Iterator)
807→		if iter.Next() {
808→			heap.Push(&c.h, iter)
809→		}
810→	}
811→	if len(overlapping) == 0 {
812→		return true
813→	}
814→
815→	// Add last as it's not yet included in overlap. We operate on same series, so labels does not matter here.
816→	iter = NewSeriesToChunkEncoder(c.mergeFunc(append(overlapping, newChunkToSeriesDecoder(labels.EmptyLabels(), c.curr))...)).Iterator(nil)
817→	if !iter.Next() {
818→		if c.err = iter.Err(); c.err != nil {
819→			return false
820→		}
821→		panic("unexpected seriesToChunkEncoder lack of iterations")
822→	}
823→	c.curr = iter.At()
824→	if iter.Next() {
825→		heap.Push(&c.h, iter)
826→	}
827→	return true
828→}
