1255→// ApplyConfig applies a new config to the DB.
1256→// Behaviour of 'OutOfOrderTimeWindow' is as follows:
1257→// OOO enabled = oooTimeWindow > 0. OOO disabled = oooTimeWindow is 0.
1258→// 1) Before: OOO disabled, Now: OOO enabled =>
1259→//   - A new WBL is created for the head block.
1260→//   - OOO compaction is enabled.
1261→//   - Overlapping queries are enabled.
1262→//
1263→// 2) Before: OOO enabled, Now: OOO enabled =>
1264→//   - Only the time window is updated.
1265→//
1266→// 3) Before: OOO enabled, Now: OOO disabled =>
1267→//   - Time Window set to 0. So no new OOO samples will be allowed.
1268→//   - OOO WBL will stay and will be eventually cleaned up.
1269→//   - OOO Compaction and overlapping queries will remain enabled until a restart or until all OOO samples are compacted.
1270→//
1271→// 4) Before: OOO disabled, Now: OOO disabled => no-op.
1272→func (db *DB) ApplyConfig(conf *config.Config) error {
1273→	oooTimeWindow := int64(0)
1274→	if conf.StorageConfig.TSDBConfig != nil {
1275→		oooTimeWindow = conf.StorageConfig.TSDBConfig.OutOfOrderTimeWindow
1276→		db.opts.staleSeriesCompactionThreshold.Store(conf.StorageConfig.TSDBConfig.StaleSeriesCompactionThreshold)
1277→		// Update retention configuration if provided.
1278→		if conf.StorageConfig.TSDBConfig.Retention != nil {
1279→			db.retentionMtx.Lock()
1280→			if conf.StorageConfig.TSDBConfig.Retention.Time > 0 {
1281→				db.opts.RetentionDuration = int64(conf.StorageConfig.TSDBConfig.Retention.Time)
1282→				db.metrics.retentionDuration.Set((time.Duration(db.opts.RetentionDuration) * time.Millisecond).Seconds())
1283→			}
1284→			if conf.StorageConfig.TSDBConfig.Retention.Size > 0 {
1285→				db.opts.MaxBytes = int64(conf.StorageConfig.TSDBConfig.Retention.Size)
1286→				db.metrics.maxBytes.Set(float64(db.opts.MaxBytes))
1287→			}
1288→			if conf.StorageConfig.TSDBConfig.Retention.Percentage > 0 {
1289→				db.opts.MaxPercentage = conf.StorageConfig.TSDBConfig.Retention.Percentage
1290→				db.metrics.maxPercentage.Set(float64(db.opts.MaxPercentage))
1291→			}
1292→			db.retentionMtx.Unlock()
1293→		}
1294→	} else {
1295→		db.opts.staleSeriesCompactionThreshold.Store(0)
1296→	}
1297→	if oooTimeWindow < 0 {
1298→		oooTimeWindow = 0
1299→	}

